1	const PROCESSING_FEE = 5;
2	const BLOCK_PRICE = 60;
3	const BLOCK_SIZE = 3;
4	
5	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; cursed?: boolean };
17	type Step = { items: Item[] };
18	type Scenario = { steps: Step[] };
19	
20	const basePremiumFor = (type: string): number =>
21	  BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
22	
23	const isBlockOfAlikeComponents = (type: string, count: number): boolean =>
24	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
25	
26	const priceForGroup = (type: string, count: number): number =>
27	  isBlockOfAlikeComponents(type, count)
28	    ? BLOCK_PRICE
29	    : count * basePremiumFor(type);
30	
31	const countByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const item of items) {
34	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
35	  }
36	  return counts;
37	};
38	
39	const sumItemPrices = (items: Item[]): number => {
40	  let total = 0;
41	  for (const [type, count] of countByType(items)) {
42	    total += priceForGroup(type, count);
43	  }
44	  for (const item of items) {
45	    if (item.cursed) total += basePremiumFor(item.type) * 0.5;
46	  }
47	  return total;
48	};
49	
50	const quotePremiumFor = (step: Step): number =>
51	  sumItemPrices(step.items) + PROCESSING_FEE;
52	
53	export const processScenario = (input: unknown): unknown => {
54	  const { steps } = input as Scenario;
55	  return { results: steps.map((step) => ({ premium: quotePremiumFor(step) })) };
56	};
