const CURSE_SURCHARGE_RATE = 0.5;

const itemSurcharge = (item: Item): number =>
  item.cursed ? basePremiumFor(item.type) * CURSE_SURCHARGE_RATE : 0;

const sumGroupedPrices = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += priceForGroup(type, count);
  }
  return total;
};

const sumItemSurcharges = (items: Item[]): number => {
  let total = 0;
  for (const item of items) {
    total += itemSurcharge(item);
  }
  return total;
};

const sumItemPrices = (items: Item[]): number =>
  sumGroupedPrices(items) + sumItemSurcharges(items);
